import React from 'react';
import { Link } from 'react-router-dom';
import { useCart } from '../context/CartContext';
import './Cart.css';

const Cart = () => {
  const { cart, loading, updateQuantity, removeFromCart } = useCart();

  if (loading) {
    return <div className="loading">Loading cart...</div>;
  }

  if (!cart || cart.items.length === 0) {
    return (
      <div className="container">
        <div className="empty-cart">
          <h2>Your cart is empty</h2>
          <p>Browse our products and add something to your cart!</p>
          <Link to="/" className="btn btn-primary mt-20">Browse Products</Link>
        </div>
      </div>
    );
  }

  const calculateTotal = () => {
    return cart.items.reduce((total, item) => {
      return total + (item.product.price * item.quantity);
    }, 0);
  };

  return (
    <div className="container">
      <h1 className="mb-20">Shopping Cart</h1>

      <div className="cart-container">
        <div className="cart-items">
          {cart.items.map(item => (
            <div key={item.product._id} className="cart-item">
              <div className="cart-item-image">
                <img src={item.product.image} alt={item.product.name} />
              </div>

              <div className="cart-item-details">
                <Link to={`/product/${item.product._id}`} className="cart-item-name">
                  {item.product.name}
                </Link>
                <p className="cart-item-category">{item.product.category}</p>
                <p className="cart-item-price">${item.product.price.toFixed(2)}</p>
              </div>

              <div className="cart-item-quantity">
                <button 
                  onClick={() => updateQuantity(item.product._id, item.quantity - 1)}
                  disabled={item.quantity <= 1}
                >-</button>
                <span>{item.quantity}</span>
                <button 
                  onClick={() => updateQuantity(item.product._id, item.quantity + 1)}
                >+</button>
              </div>

              <div className="cart-item-subtotal">
                ${(item.product.price * item.quantity).toFixed(2)}
              </div>

              <button 
                className="btn-remove"
                onClick={() => removeFromCart(item.product._id)}
              >
                &times;
              </button>
            </div>
          ))}
        </div>

        <div className="cart-summary">
          <h2>Order Summary</h2>
          <div className="summary-row">
            <span>Subtotal</span>
            <span>${calculateTotal().toFixed(2)}</span>
          </div>
          <div className="summary-row">
            <span>Shipping</span>
            <span>Free</span>
          </div>
          <div className="summary-row total">
            <span>Total</span>
            <span>${calculateTotal().toFixed(2)}</span>
          </div>
          <button className="btn btn-primary btn-block mt-20">
            Proceed to Checkout
          </button>
          <Link to="/" className="btn btn-secondary btn-block mt-10">
            Continue Shopping
          </Link>
        </div>
      </div>
    </div>
  );
};

export default Cart;
